// // This module is designed to implement a 4-bit binary counter with asynchronous reset and disable functionalities.
module counter_4bit(clk, reset, enable, count);
    input clk;
    input reset;
    input enable;
    output reg [3:0] count;

    always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else if (enable)
            count <= count + 1;
    end
endmodule
